    tech_id = responsible['tech_id']
    product_id = batch['product_id']
    window_key = (machine_id, wo_id)

    window_stats[window_key][product_id]['total'] += 1
    if batch_id in rejected_batches:
        window_stats[window_key][product_id]['rejected'] += 1

    if batch_id in rejected_batches:
        batch_attribution[batch_id] = {'wo_id': wo_id, 'tech_id': tech_id, 'machine_id': machine_id}

