        if stats['rejected'] > 0:
            fraction = stats['rejected'] / stats['total']
            # Find tech for this WO
            tech = next((ev['tech_id'] for ev in machine_maintenance.get(machine_id, []) if ev['wo_id'] == wo_id), 'UNKNOWN')
            print(f"  {machine_id}, {wo_id}, {tech}, {product_id} | {stats['rejected']}/{stats['total']} | {fraction:.3f}")
